import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon, Badge, Input, Select } from 'decantr/components';

code.example:
function TenantPaymentSetup({ tenant, paymentMethods, upcomingPayments }) {
  const { div, h1, h2, span, p, label } = tags;
  const [autopayEnabled, setAutopayEnabled] = createSignal(tenant.autopayEnabled);
  const [autopayDay, setAutopayDay] = createSignal(tenant.autopayDay || 1);
  const [showAddForm, setShowAddForm] = createSignal(false);
  const [addFormType, setAddFormType] = createSignal('bank');

  const primaryMethod = paymentMethods.find(m => m.isPrimary);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Payment Settings'),
      Badge({ variant: autopayEnabled() ? 'success' : 'default' }, autopayEnabled() ? 'Autopay On' : 'Autopay Off')
    ),
    div({ class: css('estate-card _p6') },
      h2({ class: css('_heading5 _mb4') }, 'Autopay'),
      div({ class: css('_flex _jcsb _aic _p4 _bgSurfaceRaised _r2') },
        div({},
          span({ class: css('_font500 _block') }, 'Automatic Payments'),
          p({ class: css('_textsm _fgmuted') }, 'Automatically pay rent on the same day each month')
        ),
        Button({
          variant: autopayEnabled() ? 'primary' : 'outline',
          onclick: () => setAutopayEnabled(!autopayEnabled())
        }, autopayEnabled() ? 'Enabled' : 'Enable')
      ),
      autopayEnabled() ? div({ class: css('_mt4 _flex _aic _gap4') },
        label({ class: css('_textsm _font500') }, 'Pay on day'),
        Select({ value: autopayDay(), onchange: e => setAutopayDay(parseInt(e.target.value)) },
          ...Array.from({ length: 28 }, (_, i) => tags.option({ value: i + 1 }, `${i + 1}${getOrdinalSuffix(i + 1)}`))
        ),
        span({ class: css('_textsm _fgmuted') }, 'of each month')
      ) : null
    ),
    div({ class: css('estate-card _p6') },
      div({ class: css('_flex _jcsb _aic _mb4') },
        h2({ class: css('_heading5') }, 'Payment Methods'),
        Button({ variant: 'outline', size: 'sm', onclick: () => setShowAddForm(true) }, icon('plus'), 'Add Method')
      ),
      paymentMethods.length === 0 ? div({ class: css('_p6 _tc _bgSurfaceRaised _r2') },
        icon('credit-card', { size: '32', class: css('_fgmuted _mb2') }),
        p({ class: css('_fgmuted _mb4') }, 'No payment methods saved'),
        Button({ variant: 'primary', onclick: () => setShowAddForm(true) }, icon('plus'), 'Add Payment Method')
      ) : div({ class: css('_flex _col _gap3') },
        ...paymentMethods.map(method =>
          div({ class: css(`_flex _aic _gap4 _p4 _r2 ${method.isPrimary ? '_borderPrimary _border[2px]' : '_border'}`) },
            icon(method.type === 'bank' ? 'building' : 'credit-card', { size: '24' }),
            div({ class: css('_flex1') },
              span({ class: css('_font500 _block') }, method.type === 'bank' ? `${method.bankName} ****${method.last4}` : `${method.brand} ****${method.last4}`),
              span({ class: css('_textsm _fgmuted') }, method.type === 'bank' ? 'Bank Account' : `Expires ${method.expMonth}/${method.expYear}`)
            ),
            method.isPrimary ? Badge({ variant: 'success' }, 'Primary') : Button({ variant: 'ghost', size: 'sm' }, 'Set Primary'),
            Button({ variant: 'ghost', size: 'sm' }, icon('trash', { size: '16' }))
          )
        )
      ),
      showAddForm() ? div({ class: css('_mt6 _pt6 _borderT') },
        h2({ class: css('_heading6 _mb4') }, 'Add Payment Method'),
        div({ class: css('_flex _gap2 _mb4') },
          Button({ variant: addFormType() === 'bank' ? 'default' : 'outline', onclick: () => setAddFormType('bank') }, icon('building'), 'Bank Account'),
          Button({ variant: addFormType() === 'card' ? 'default' : 'outline', onclick: () => setAddFormType('card') }, icon('credit-card'), 'Card')
        ),
        addFormType() === 'bank' ? BankAccountForm() : CardForm(),
        div({ class: css('_flex _jce _gap2 _mt4') },
          Button({ variant: 'outline', onclick: () => setShowAddForm(false) }, 'Cancel'),
          Button({ variant: 'primary' }, 'Save Payment Method')
        )
      ) : null
    ),
    upcomingPayments.length > 0 ? div({ class: css('estate-card _p6') },
      h2({ class: css('_heading5 _mb4') }, 'Upcoming Payments'),
      div({ class: css('_flex _col _gap3') },
        ...upcomingPayments.map(payment =>
          div({ class: css('_flex _jcsb _aic _p4 _bgSurfaceRaised _r2') },
            div({},
              span({ class: css('_font500 _block') }, payment.description),
              span({ class: css('_textsm _fgmuted') }, new Date(payment.dueDate).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' }))
            ),
            span({ class: css('_heading5') }, `$${payment.amount.toLocaleString()}`)
          )
        )
      )
    ) : null
  );
}

function BankAccountForm() {
  const { div, label } = tags;
  return div({ class: css('_grid _cols2 _gap4') },
    div({},
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Routing Number'),
      Input({ type: 'text', placeholder: '9 digits', maxlength: 9 })
    ),
    div({},
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Account Number'),
      Input({ type: 'text', placeholder: 'Account number' })
    ),
    div({},
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Account Type'),
      Select({},
        tags.option({ value: 'checking' }, 'Checking'),
        tags.option({ value: 'savings' }, 'Savings')
      )
    ),
    div({},
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Account Holder Name'),
      Input({ type: 'text', placeholder: 'Name on account' })
    )
  );
}

function CardForm() {
  const { div, label } = tags;
  return div({ class: css('_grid _cols2 _gap4') },
    div({ class: css('_col[span-2]') },
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Card Number'),
      Input({ type: 'text', placeholder: '1234 5678 9012 3456', maxlength: 19 })
    ),
    div({},
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Expiration'),
      Input({ type: 'text', placeholder: 'MM/YY', maxlength: 5 })
    ),
    div({},
      label({ class: css('_textsm _font500 _mb1 _block') }, 'CVC'),
      Input({ type: 'text', placeholder: '123', maxlength: 4 })
    ),
    div({ class: css('_col[span-2]') },
      label({ class: css('_textsm _font500 _mb1 _block') }, 'Name on Card'),
      Input({ type: 'text', placeholder: 'Full name' })
    )
  );
}

function getOrdinalSuffix(n) {
  const s = ['th', 'st', 'nd', 'rd'];
  const v = n % 100;
  return s[(v - 20) % 10] || s[v] || s[0];
}

